DECLARE LastCacheRefreshTime_token SHARED TIMESTAMP;
DECLARE Bearer_token SHARED CHARACTER '';

-- Check cache validity
IF (LastCacheRefreshTime_token IS NULL OR 
    (CAST((CURRENT_TIMESTAMP - LastCacheRefreshTime_token) SECOND AS FLOAT) > 86400)) THEN
  -- Refresh token
END IF;

